CREATE DEFINER=`root`@`%` PROCEDURE `getActiveModulesWithPermissionsForSuperAdmin` ()   BEGIN
    SELECT 
        modules.id AS module_id,
        modules.module_group,
        modules.module_name,
        modules.description AS modules_description,
        permissions.id AS permissions_id,
        permissions.name AS permissions_name,
        permissions.display_name AS permissions_display_name
    FROM modules
    INNER JOIN permissions ON modules.id = permissions.module_id
    WHERE 
        modules.is_superadmin = 1  -- Ensure the correct table reference
        AND modules.status = 'active' 
        AND permissions.status = 'active'
    ORDER BY 
        modules.order_by ASC, 
        permissions.order_by ASC;
END$$

CREATE DEFINER=`root`@`%` PROCEDURE `getUserModulesWithPermissionsForOtherUsers` (IN `userId` INT)   BEGIN
    SELECT 
        modules.module_group AS module_group,
        modules.id AS module_id,
        modules.module_name AS module_name,
        modules.description AS modules_description,
        permissions.id AS permissions_id,
        permissions.name AS permissions_name,
        permissions.display_name AS permissions_display_name
    FROM permissions
    INNER JOIN modules ON permissions.module_id = modules.id
    INNER JOIN permission_role ON permissions.id = permission_role.permission_id
    INNER JOIN role_user ON permission_role.role_id = role_user.role_id
    WHERE 
        role_user.user_id = userId
        AND role_user.status = 'active'
        AND permission_role.status = 'active'
        AND permission_role.permission_type_id != '5'
        AND modules.is_superadmin !=1
    ORDER BY modules.module_group, modules.id, permissions.id;
END$$

CREATE DEFINER=`root`@`%` PROCEDURE `ProcedureCopyModuleSettings` (IN `p_newCompanyId` INT)   BEGIN
    
    SELECT p_newCompanyId, module_name, status, type, NOW(), NOW(), is_allowed FROM module_settings WHERE company_id = 1;
END$$

CREATE DEFINER=`root`@`%` PROCEDURE `ProcedureCopyRolesAndPermissions` (IN `p_newCompanyId` INT)   BEGIN
    DECLARE newRoleId INT;
    DECLARE oldRoleId INT;

    
    DECLARE role_cursor CURSOR FOR 
    SELECT id FROM roles WHERE company_id = 1;

    DECLARE CONTINUE HANDLER FOR NOT FOUND SET oldRoleId = NULL;

    OPEN role_cursor;

    role_loop: LOOP
        FETCH role_cursor INTO oldRoleId;
        IF oldRoleId IS NULL THEN 
            LEAVE role_loop;
        END IF;

        
        SELECT p_newCompanyId, name, display_name, description, NOW(), NOW()
        FROM roles WHERE id = oldRoleId;

        SET newRoleId = LAST_INSERT_ID(); 

        
        SELECT permission_id, newRoleId, permission_type_id
        FROM permission_role WHERE role_id = oldRoleId;
    END LOOP;

    CLOSE role_cursor;
END$$

CREATE DEFINER=`root`@`%` PROCEDURE `ProcedureInsertCompanyAndUsers` (IN `p_name` VARCHAR(100), IN `p_email` VARCHAR(191), IN `p_currency` VARCHAR(10), IN `p_timezone` VARCHAR(50), IN `p_language` VARCHAR(50), IN `p_address` VARCHAR(255), IN `p_phone` VARCHAR(255), IN `p_website` VARCHAR(255), IN `p_logo` VARCHAR(255), IN `p_accountName` VARCHAR(100), IN `p_accountEmail` VARCHAR(191), IN `p_defaultPassword` VARCHAR(100), OUT `p_newCompanyId` INT)   BEGIN
    DECLARE newCompanyId INT;
    DECLARE newUserAuthId INT;

    
    VALUES (p_name, p_email, p_currency, p_timezone, NOW(), NOW(),p_address,p_phone,p_website,p_logo);

    SET newCompanyId = LAST_INSERT_ID(); 
    SET p_newCompanyId = newCompanyId;  

    
    VALUES (p_accountEmail, p_defaultPassword, NOW(), NOW());

    SET newUserAuthId = LAST_INSERT_ID(); 

    
    VALUES (p_accountName, p_accountEmail, newCompanyId, newUserAuthId, NOW(), NOW());

END$$

